#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

#define IN_RANGE(x, min, max) ((x) >= (min) && (x) <= (max))

__kernel void hotspot(
    int iteration,
    __global float *power,
    __global float *temp_src,
    __global float *temp_dst,
    int grid_cols,
    int grid_rows,
    int border_cols,
    int border_rows,
    float Cap,
    float Rx,
    float Ry,
    float Rz,
    float step)
{
    const float amb_temp = 80.0f;

    int bx = get_group_id(0);
    int by = get_group_id(1);

    int tx = get_local_id(0);
    int ty = get_local_id(1);

    int small_block_cols = BLOCK_SIZE - iteration * 2;
    int small_block_rows = BLOCK_SIZE - iteration * 2;

    int blkX = small_block_cols * bx - border_cols;
    int blkY = small_block_rows * by - border_rows;

    int xidx = blkX + tx;
    int yidx = blkY + ty;

    int load_x = xidx;
    int load_y = yidx;

    if (load_x < 0) load_x = 0;
    if (load_x > grid_cols - 1) load_x = grid_cols - 1;
    if (load_y < 0) load_y = 0;
    if (load_y > grid_rows - 1) load_y = grid_rows - 1;

    int load_index = load_y * grid_cols + load_x;

    __local float temp_l[BLOCK_SIZE][BLOCK_SIZE];
    __local float power_l[BLOCK_SIZE][BLOCK_SIZE];

    temp_l[ty][tx] = temp_src[load_index];
    power_l[ty][tx] = power[load_index];

    barrier(CLK_LOCAL_MEM_FENCE);

    int valid_x_min = (blkX < 0) ? -blkX : 0;
    int valid_y_min = (blkY < 0) ? -blkY : 0;
    int valid_x_max = (blkX + BLOCK_SIZE > grid_cols) ? (grid_cols - blkX - 1) : (BLOCK_SIZE - 1);
    int valid_y_max = (blkY + BLOCK_SIZE > grid_rows) ? (grid_rows - blkY - 1) : (BLOCK_SIZE - 1);

    float temp_t = temp_l[ty][tx];

    int N = ty - 1;
    int S = ty + 1;
    int W = tx - 1;
    int E = tx + 1;

    int computed;

    for (int i = 0; i < iteration; i++) {
        computed =
            IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) &&
            IN_RANGE(ty, i + 1, BLOCK_SIZE - i - 2) &&
            IN_RANGE(tx, valid_x_min, valid_x_max) &&
            IN_RANGE(ty, valid_y_min, valid_y_max);

        if (computed) {
            float center = temp_l[ty][tx];
            float north = temp_l[N][tx];
            float south = temp_l[S][tx];
            float west  = temp_l[ty][W];
            float east  = temp_l[ty][E];

            float delta =
                (power_l[ty][tx]) +
                (south + north - 2.0f * center) / Ry +
                (east + west - 2.0f * center) / Rx +
                (amb_temp - center) / Rz;

            temp_t = center + (step / (Cap * 1000.0f)) * delta;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if (i == iteration - 1) break;

        if (computed) {
            temp_l[ty][tx] = temp_t;
        }

        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (IN_RANGE(tx, iteration, BLOCK_SIZE - iteration - 1) &&
        IN_RANGE(ty, iteration, BLOCK_SIZE - iteration - 1) &&
        IN_RANGE(tx, valid_x_min, valid_x_max) &&
        IN_RANGE(ty, valid_y_min, valid_y_max)) {
        int out_index = yidx * grid_cols + xidx;
        temp_dst[out_index] = temp_t;
    }
}
